import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const DAYS = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"];


const FAQS = [
  { q: "How do I calculate my total weekly hours?", a: "Add up the hours worked each day. This calculator automatically computes daily hours from your time-in and time-out entries (subtracting your break time) and sums the week. If you work 8h 30m Mon-Fri, your total is 42.5 hours. Hours beyond 40 are automatically counted as overtime." },
  { q: "How is overtime calculated?", a: "Under US federal law (FLSA), overtime pay is required for hours worked beyond 40 in a workweek at 1.5 x  (time and a half) the regular rate. Some states have daily overtime requirements: California requires overtime after 8 hours per day and double-time after 12 hours. This calculator uses the federal 40-hour weekly overtime rule." },
  { q: "Should I include lunch breaks?", a: "It depends on your employer's policy. Most 30-minute unpaid meal breaks should be excluded. Enter your break duration in minutes for each day and the calculator will subtract it from that day's hours. Paid breaks (typically 10-15 minute rest breaks) are included in work time and should not be entered as breaks." },
  { q: "How do I convert minutes to decimal hours?", a: "Divide the minutes by 60. Examples: 15 min = 0.25 hrs, 20 min = 0.333 hrs, 30 min = 0.50 hrs, 45 min = 0.75 hrs. For payroll purposes, decimal hours  x  hourly rate = pay. 40.5 hours  x  $20/hr = $810. Many payroll systems use decimal hours rather than HH:MM format." },
  { q: "What counts as a workweek for overtime purposes?", a: "The FLSA defines a workweek as any fixed, regularly recurring period of 168 hours - seven consecutive 24-hour periods. It doesn't have to be Monday-Sunday. Employers set the workweek start day. Overtime is calculated per workweek - you cannot average two weeks together. Each week is evaluated independently." },
  { q: "What is double-time pay and when does it apply?", a: "Double-time pay (2 x  regular rate) is not federally required, but is mandated in California for: hours over 12 in a workday, or hours over 8 on the 7th consecutive workday in a week. Some union contracts require double-time for weekends, holidays, or specific shifts. This calculator shows federal overtime (1.5 x ) only." },
  { q: "How do I calculate pay for tipped employees?", a: "Federal minimum wage for tipped employees is $2.13/hr if tips bring total to at least $7.25/hr (the federal minimum). If tips don't cover the gap, the employer must make up the difference. Many states have higher tipped minimum wages. Overtime for tipped employees: 1.5 x  of the full minimum wage, not the tipped rate." },
  { q: "What is comp time and how does it work?", a: "Compensatory time off (comp time) is paid time off given in lieu of overtime pay. Private-sector employers covered by the FLSA must pay overtime in cash - they cannot legally substitute comp time for overtime. State and local government employers may offer comp time under certain conditions. Always check your employment contract and local laws." },
];

const HOURS_REFERENCE = [
  ["Part-time", "20 hrs/week", "$20/hr", "$400/week", "$0"],
  ["Standard", "40 hrs/week", "$20/hr", "$800/week", "$0"],
  ["Mild OT", "45 hrs/week", "$20/hr", "$950/week", "$150"],
  ["Moderate OT", "50 hrs/week", "$20/hr", "$1,100/week", "$300"],
  ["Heavy OT", "60 hrs/week", "$20/hr", "$1,400/week", "$600"],
  ["Max OT", "70 hrs/week", "$20/hr", "$1,700/week", "$900"],
];

function timeToMinutes(t: string): number {
  if (!t) return 0;
  const [h, m] = t.split(":").map(Number);
  return h * 60 + m;
}

export default function TimeCardCalculator() {
  useCurrencyVersion();
  const [entries, setEntries] = useState(DAYS.map(() => ({ in: "", out: "", break: 0 })));
  const [hourlyRate, setHourlyRate] = useState(20);

  const update = (i: number, field: "in" | "out" | "break", val: string | number) =>
    setEntries(e => e.map((r, idx) => idx === i ? { ...r, [field]: val } : r));

  const dailyHours = entries.map(e => {
    if (!e.in || !e.out) return 0;
    const mins = timeToMinutes(e.out) - timeToMinutes(e.in) - Number(e.break);
    return Math.max(0, mins / 60);
  });
  const totalHours = dailyHours.reduce((s, h) => s + h, 0);
  const regularHours = Math.min(totalHours, 40);
  const overtimeHours = Math.max(0, totalHours - 40);
  const totalPay = regularHours * hourlyRate + overtimeHours * hourlyRate * 1.5;

  return (
    <>
      <SEOHead
        title="Free Time Card Calculator Online - Calculate Work Hours and Overtime Instantly | CalcHive"
        description="Free online time card calculator. Calculate total weekly hours and pay from daily time-in and time-out entries including overtime instantly. 100% free for everyone, no signup required."
        canonical="/time-card-calculator"
        keywords="free time card calculator, timesheet calculator free online, weekly hours overtime calculator free, time in time out calculator free, free payroll hours calculator"
        category="Date & Time Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-orange-600 dark:text-orange-400 bg-orange-50 dark:bg-orange-950/50 px-3 py-1 rounded-full mb-4 inline-block">Date &amp; Time</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Time Card Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free time card calculator to calculate weekly hours, overtime, and pay from daily time in and time out entries. This timesheet calculator free online also works as a weekly hours overtime calculator free, time in time out calculator free, and free payroll hours calculator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-6">
            <label className="text-sm font-semibold text-foreground mb-2 block">Hourly Rate ($)</label>
            <input type="number" value={hourlyRate} min={0} step={0.5} onChange={e => setHourlyRate(Number(e.target.value))}
              className="w-48 px-4 py-2 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm" />
          </div>
          <div className="overflow-x-auto mb-6">
            <table className="w-full text-sm">
              <thead><tr className="border-b border-border">
                <th className="text-left py-2 font-semibold text-muted-foreground">Day</th>
                <th className="text-left py-2 font-semibold text-muted-foreground">Time In</th>
                <th className="text-left py-2 font-semibold text-muted-foreground">Time Out</th>
                <th className="text-left py-2 font-semibold text-muted-foreground">Break (min)</th>
                <th className="text-right py-2 font-semibold text-muted-foreground">Hours</th>
              </tr></thead>
              <tbody>
                {DAYS.map((day, i) => (
                  <tr key={day} className="border-b border-border/50">
                    <td className="py-2 pr-2 font-medium text-foreground">{day}</td>
                    <td className="py-2 pr-2"><input type="time" value={entries[i].in} onChange={e => update(i, "in", e.target.value)} className="px-2 py-1 rounded-lg border border-border bg-background text-foreground text-xs focus:outline-none focus:ring-2 focus:ring-primary/40" /></td>
                    <td className="py-2 pr-2"><input type="time" value={entries[i].out} onChange={e => update(i, "out", e.target.value)} className="px-2 py-1 rounded-lg border border-border bg-background text-foreground text-xs focus:outline-none focus:ring-2 focus:ring-primary/40" /></td>
                    <td className="py-2 pr-2"><input type="number" value={entries[i].break || ""} min={0} max={480} onChange={e => update(i, "break", e.target.value)} className="w-16 px-2 py-1 rounded-lg border border-border bg-background text-foreground text-xs focus:outline-none focus:ring-2 focus:ring-primary/40" /></td>
                    <td className="py-2 text-right font-bold text-foreground">{dailyHours[i] > 0 ? dailyHours[i].toFixed(2) : "-"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <motion.div key={totalHours.toFixed(2)} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-orange-500 to-orange-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated Weekly Pay</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-pay">{formatCurrencyValue(totalPay)}</p>
              <p className="text-white/70 text-sm mt-1">{totalHours.toFixed(2)} total hours - ${hourlyRate}/hr</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "Regular Hours", value: `${regularHours.toFixed(2)} hrs` },
                { label: "Overtime Hours", value: `${overtimeHours.toFixed(2)} hrs`, orange: overtimeHours > 0 },
                { label: "OT Pay (1.5 x )", value: formatCurrencyValue(overtimeHours * hourlyRate * 1.5) },
              ].map(({ label, value, orange }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-base font-extrabold ${orange ? "text-orange-600 dark:text-orange-400" : "text-foreground"}`}>{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Weekly Work Hours and Overtime for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Daily Hours = (Clock Out - Clock In) - Break (in hours)</p>
            <p>Total Hours = Sum of all daily hours</p>
            <p>Regular Pay = min(Total Hours, 40)  x  Hourly Rate</p>
            <p>OT Hours = max(0, Total Hours - 40)</p>
            <p>OT Pay = OT Hours  x  Hourly Rate  x  1.5</p>
            <p>Total Pay = Regular Pay + OT Pay</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Track Daily Time In and Time Out Entries</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Schedule", "Weekly Hours", "Rate", "Weekly Pay", "OT Pay"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {HOURS_REFERENCE.map(([sched, hrs, rate, pay, ot]) => (
                  <tr key={sched} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{sched}</td>
                    <td className="py-2.5 px-4 text-orange-600 dark:text-orange-400 font-bold">{hrs}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{rate}</td>
                    <td className="py-2.5 px-4 font-bold text-foreground">{pay}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{ot}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Timesheet Calculator for Employees and Managers</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free date and time tool on any device to compare schedules, track durations, and get instant results without signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/time-card-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


